function normalizeKey(text) {
    return (text ?? "").toLowerCase().replace(/[\s_]+/g, "");
}

function compareCategoryNames(a, b) {
    const aKey = normalizeKey(a);
    const bKey = normalizeKey(b);
    const aRank = ORDER_DATA.categoryRank[aKey];
    const bRank = ORDER_DATA.categoryRank[bKey];

    const aHas = typeof aRank === "number";
    const bHas = typeof bRank === "number";

    if (aHas && bHas && aRank !== bRank) return aRank - bRank;
    if (aHas && !bHas) return -1;
    if (!aHas && bHas) return 1;
    return a.localeCompare(b);
}

function comparePropertyNamesWithinCategory(categoryName, aPropertyName, bPropertyName, nodeClassName) {
    const categoryKey = normalizeKey(categoryName);
    const map = ORDER_DATA.propertyRankByCategory[categoryKey];
    if (!map) {
        // Debug logging for misses
        if (typeof window !== 'undefined' && window.PROPERTY_SORTER_DEBUG) {
            console.log(`Property sorter fallback: ${categoryName} - "${aPropertyName}" vs "${bPropertyName}" (class: ${nodeClassName || 'none'})`);
        }
        return aPropertyName.localeCompare(bPropertyName);
    }

    const aFull = nodeClassName ? normalizeKey(`${nodeClassName}.${aPropertyName}`) : "";
    const bFull = nodeClassName ? normalizeKey(`${nodeClassName}.${bPropertyName}`) : "";
    const aShort = normalizeKey(aPropertyName);
    const bShort = normalizeKey(bPropertyName);

    const aRank = (aFull && map[aFull] !== undefined) ? map[aFull] : map[aShort];
    const bRank = (bFull && map[bFull] !== undefined) ? map[bFull] : map[bShort];

    const aHas = typeof aRank === "number";
    const bHas = typeof bRank === "number";

    if (aHas && bHas && aRank !== bRank) return aRank - bRank;
    if (aHas && !bHas) return -1;
    if (!aHas && bHas) return 1;

    // Debug logging for misses
    if (typeof window !== 'undefined' && window.PROPERTY_SORTER_DEBUG) {
        console.log(`Property sorter fallback: ${categoryName} - "${aPropertyName}" vs "${bPropertyName}" (class: ${nodeClassName || 'none'})`);
    }
    return aPropertyName.localeCompare(bPropertyName);
}
